package main

import "fmt"

func fibonacci(n int) []int {
    fibSequence := make([]int, n)
    for i := 0; i < n; i++ {
        if i <= 1 {
            fibSequence[i] = i
        } else {
            fibSequence[i] = fibSequence[i-1] + fibSequence[i-2]
        }
    }
    return fibSequence
}

